const fileContent = $input.first().json.stdout || '';
const project = $('Webhook').first().json.query.project;
const status = $('Webhook').first().json.query.status || '';
const section = $('Webhook').first().json.query.section || 'Log';

if (fileContent.trim() === 'FILE_NOT_FOUND') {
  return [{ json: { hasError: true, errorType: 'file_not_found', project } }];
}

if (!status.trim()) {
  return [{ json: { hasError: true, errorType: 'empty_status', project } }];
}

// Format timestamp as YYYY-MM-DD HH:mm
const now = new Date();
const ts = now.toISOString().slice(0, 16).replace('T', ' ');
const entry = `- ${ts} — ${status.trim()}`;

let updated = fileContent;

// Find the target section (## Log by default) and append entry
const sectionRegex = new RegExp(`(## ${section}[\\r\\n]([\\s\\S]*?))(?=[\\n]## |[\\n]---|$)`, 'm');
const sectionMatch = updated.match(sectionRegex);

if (sectionMatch) {
  const sectionContent = sectionMatch[1];
  const insertPos = updated.indexOf(sectionContent) + sectionContent.length;
  // Trim trailing whitespace from section, add entry, then rest
  const before = updated.slice(0, insertPos).trimEnd();
  const after = updated.slice(insertPos);
  updated = before + '\n' + entry + after;
} else {
  // No matching section — append ## Log at the end
  updated = updated.trimEnd() + '\n\n## Log\n' + entry + '\n';
}

const base64Content = Buffer.from(updated).toString('base64');
return [{ json: { hasError: false, base64Content, project, status: status.trim(), timestamp: ts } }];
